package com.example.eventstreamingplatform.model;

public class EventMessage {
    private String id;
    private String type;
    private String payload;

    public EventMessage() {
    }

    public EventMessage(String id, String type, String payload) {
        this.id = id;
        this.type = type;
        this.payload = payload;
    }

    public String getId() {
        return id;
    }

    public void setId(String id) {
        this.id = id;
    }

    public String getType() {
        return type;
    }

    public void setType(String type) {
        this.type = type;
    }

    public String getPayload() {
        return payload;
    }

    public void setPayload(String payload) {
        this.payload = payload;
    }

    @Override
    public String toString() {
        return "EventMessage{" +
                "id='" + id + '\'' +
                ", type='" + type + '\'' +
                ", payload='" + payload + '\'' +
                '}';
    }
}

package com.example.eventstreamingplatform.service;

import com.example.eventstreamingplatform.model.EventMessage;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.kafka.core.KafkaTemplate;
import org.springframework.stereotype.Service;

@Service
public class EventProducerService {

    private final KafkaTemplate<String, String> kafkaTemplate;
    private final String topicName;

    public EventProducerService(KafkaTemplate<String, String> kafkaTemplate,
                                @Value("${app.kafka.topic:events}") String topicName) {
        this.kafkaTemplate = kafkaTemplate;
        this.topicName = topicName;
    }

    public void publishEvent(EventMessage eventMessage) {
        kafkaTemplate.send(topicName, eventMessage.getId(), eventMessage.toString());
    }

    public void publishRawMessage(String key, String message) {
        kafkaTemplate.send(topicName, key, message);
    }
}

package com.example.eventstreamingplatform.service;

import org.springframework.kafka.annotation.KafkaListener;
import org.springframework.stereotype.Service;

@Service
public class EventConsumerService {

    @KafkaListener(topics = "${app.kafka.topic:events}", groupId = "event-streaming-platform-group")
    public void consume(String message) {
        System.out.println("Consumed message: " + message);
    }
}

package com.example.eventstreamingplatform.controller;

import com.example.eventstreamingplatform.model.EventMessage;
import com.example.eventstreamingplatform.service.EventProducerService;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;

import java.util.UUID;

@RestController
@RequestMapping("/api/events")
public class EventController {

    private final EventProducerService eventProducerService;

    public EventController(EventProducerService eventProducerService) {
        this.eventProducerService = eventProducerService;
    }

    @PostMapping
    public ResponseEntity<String> publish(@RequestBody EventMessage request) {
        if (request.getId() == null || request.getId().isBlank()) {
            request.setId(UUID.randomUUID().toString());
        }
        eventProducerService.publishEvent(request);
        return ResponseEntity.ok("Event published");
    }

    @PostMapping("/raw")
    public ResponseEntity<String> publishRaw(@RequestParam String key, @RequestBody String message) {
        eventProducerService.publishRawMessage(key, message);
        return ResponseEntity.ok("Raw message published");
    }
}

